SET DEFINE OFF
ALTER SESSION SET NLS_LENGTH_SEMANTICS = 'CHAR';

BEGIN EXECUTE IMMEDIATE 'DROP VIEW HR_VIEW'; EXCEPTION WHEN OTHERS THEN IF SQLCODE != -942 THEN RAISE; END IF; END;
/
BEGIN EXECUTE IMMEDIATE 'DROP TABLE HR_TABLE PURGE'; EXCEPTION WHEN OTHERS THEN IF SQLCODE != -942 THEN RAISE; END IF; END;
/

WHENEVER SQLERROR EXIT SQL.SQLCODE

CREATE TABLE HR_TABLE (
  EMPN    VARCHAR2(10)  NOT NULL,
  NAME    VARCHAR2(50),
  UNITCD  VARCHAR2(10),
  CUNIT   VARCHAR2(100),
  EUNIT   VARCHAR2(200),
  UNITCD1 VARCHAR2(10),
  CUNIT1  VARCHAR2(100),
  EUNIT1  VARCHAR2(200),
  UNITCD2 VARCHAR2(10),
  CUNIT2  VARCHAR2(100),
  EUNIT2  VARCHAR2(200),
  UNITCD3 VARCHAR2(10),
  CUNIT3  VARCHAR2(100),
  EUNIT3  VARCHAR2(200),
  UNITLVL NUMBER(2),
  EMAIL   VARCHAR2(200),
  CONSTRAINT PK_HR_TABLE PRIMARY KEY (EMPN)
);


COMMIT;

CREATE OR REPLACE VIEW HR_VIEW AS SELECT * FROM HR_TABLE;

SELECT COUNT(*) AS HR_TABLE_CNT FROM HR_TABLE;
SELECT COUNT(*) AS HR_VIEW_CNT  FROM HR_VIEW;
EXIT;